tactics.medic:
class Tactic:
    def __init__(self):
        pass
    def tick(self, me, world):
        allies = world.visible_allies()
        for ally in allies:
            if ally.hp < ally.max_hp and me.cooldown == 0 and me.can_heal(ally):
                return me.heal(ally)
        if me.move_cd == 0:
            if allies:
                closest = min(allies, key=lambda u: me.distance_to(u.pos))
                return me.move_toward(closest.pos)
            else:
                return me.move_toward(world.center)
        return me.hold()

